import React from "react";

export default function ModalTratamentoFace({ open, face, dente, onClose, onSave }) {
  if (!open) return null;

  // Lista de tratamentos para selecionar (exemplo)
  const tratamentos = [
    "Obturação",
    "Canal",
    "Limpeza",
    "Extração",
    "Faceta",
    "Outro"
  ];

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center">
      <div className="bg-white rounded-xl shadow-xl p-8 max-w-xs">
        <h3 className="font-bold mb-4 text-lg">
          Tratamento para Dente {dente} ({face})
        </h3>
        <ul>
          {tratamentos.map(t => (
            <li key={t}>
              <button
                onClick={() => onSave({ dente, face, tratamento: t })}
                className="block w-full text-left py-2 hover:bg-gray-100 rounded"
              >
                {t}
              </button>
            </li>
          ))}
        </ul>
        <button
          onClick={onClose}
          className="mt-6 px-4 py-2 rounded bg-gray-300 text-gray-700 hover:bg-gray-400"
        >
          Cancelar
        </button>
      </div>
    </div>
  );
}
